  1 import Foundation
  2 
  3 public actor StartupMigrationRunner {
  4     public static let defaultFileName = "migrations.json"
  5 
  6     private static let removeUnknownAccountsMigrationID = "remove-account-unknown-placeholders"
  7 
  8     private let fileManager: UsagesFileManager
  9     private let migrationsFilePath: String
 10     private let logger: FileLogger
 11     private let now: @Sendable () -> Date
 12 
 13     public init(
 14         fileManager: UsagesFileManager = .shared,
 15         migrationsFilePath: String? = nil,
 16         logger: FileLogger = Loggers.app,
 17         now: @escaping @Sendable () -> Date = Date.init
 18     ) {
 19         let home = FileManager.default.homeDirectoryForCurrentUser.path
 20         let cacheDir = "\(home)/.cache/ai-usages-tracker"
 21         self.fileManager = fileManager
 22         self.migrationsFilePath = migrationsFilePath ?? "\(cacheDir)/\(Self.defaultFileName)"
 23         self.logger = logger
 24         self.now = now
 25     }
 26 
 27     public func run() async {
 28         var file = readMigrationsFile()
 29         guard !file.hasApplied(Self.removeUnknownAccountsMigrationID) else {
 30             logger.log(.debug, "Startup migration already applied: \(Self.removeUnknownAccountsMigrationID)")
 31             return
 32         }
 33 
 34         guard await fileManager.removeAccountUnknownPlaceholders() else {
 35             logger.log(.warning, "Startup migration failed: \(Self.removeUnknownAccountsMigrationID)")
 36             return
 37         }
 38 
 39         file.applied.append(AppliedStartupMigration(
 40             id: Self.removeUnknownAccountsMigrationID,
 41             appliedAt: ISODate(date: now())
 42         ))
 43         writeMigrationsFile(file)
 44         logger.log(.info, "Startup migration applied: \(Self.removeUnknownAccountsMigrationID)")
 45     }
 46 
 47     private func readMigrationsFile() -> StartupMigrationsFile {
 48         guard let data = FileManager.default.contents(atPath: migrationsFilePath) else {
 49             return StartupMigrationsFile()
 50         }
 51         do {
 52             return try JSONDecoder().decode(StartupMigrationsFile.self, from: data)
 53         } catch {
 54             logger.log(.warning, "Failed to decode \(migrationsFilePath); rebuilding migrations file: \(error)")
 55             return StartupMigrationsFile()
 56         }
 57     }
 58 
 59     private func writeMigrationsFile(_ file: StartupMigrationsFile) {
 60         let dir = (migrationsFilePath as NSString).deletingLastPathComponent
 61         do {
 62             try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
 63         } catch {
 64             logger.log(.error, "Failed to create migrations directory \(dir): \(error)")
 65             return
 66         }
 67 
 68         let encoder = JSONEncoder()
 69         encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
 70         do {
 71             let data = try encoder.encode(file)
 72             try data.write(to: URL(fileURLWithPath: migrationsFilePath), options: .atomic)
 73         } catch {
 74             logger.log(.error, "Failed to write migrations file \(migrationsFilePath): \(error)")
 75         }
 76     }
 77 }
 78 
 79 public struct StartupMigrationsFile: Codable, Equatable, Sendable {
 80     public var applied: [AppliedStartupMigration]
 81 
 82     public init(applied: [AppliedStartupMigration] = []) {
 83         self.applied = applied
 84     }
 85 
 86     public func hasApplied(_ id: String) -> Bool {
 87         applied.contains { $0.id == id }
 88     }
 89 }
 90 
 91 public struct AppliedStartupMigration: Codable, Equatable, Sendable {
 92     public let id: String
 93     public let appliedAt: ISODate
 94 
 95     public init(id: String, appliedAt: ISODate) {
 96         self.id = id
 97         self.appliedAt = appliedAt
 98     }
 99 }

